INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('人力资源实习生（项目 / 数据分析方向）-北京', '互联网 / IT', '北京', '民营企业', 80, 120, '1. 大专及以上学历（本科优先，如数据处理能力优秀或有人力 / 财务相关工作经验，可放宽至大专）； 2. 对数据敏感，擅长使用 Excel； 3. 具备基础的人力资源项目协助能力。', '1. 学习能力强，积极主动，抗逆性较好； 2. 具备优秀的沟通表达能力与团队协作能力； 3. 工作细致，有责任心，能高效完成多任务。', 1, '极度友好', '1. 协助灵活用工人员完成入职 / 离职申报； 2. 使用 Excel 处理灵活用工项目员工薪资数据拆分及复核（需熟练掌握函数如 XLOOKUP、VLOOKUP）； 3. 使用灵活用工系统完成薪资发放及发薪失败的再次核对； 4. 其他项目支持性工作：如结算单打印清单、整理项目台账等。', '招聘全流程执行, 薪酬绩效支持, 员工关系支持', '大专及以上', '人力资源管理、工商管理、财务管理 / 统计等工商管理类专业优先，欢迎有相关专业背景或实习经验的应届生同学', '在校大学生，可连续实习至少 3 个月，每周到岗 5 天，有 HR 相关实习 / 兼职经验优先', '日常实习', '1. 有互联网 / 乙方人力资源服务 / 财务 / 管理 / 统计等工商管理类实习经验； 2. 具备较强的数据分析意识； 3. 有校园活动组织经验。', '100元/天', '46083', '46276', 'https://www.shixiseng.com/intern/inn_uqrkra7mvoua?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('人力资源实习生 - 绵阳（实习）', '制造', '绵阳', '民营企业', 120, 150, '熟练使用 Office 办公软件，具备良好的文字功底', '对人力资源领域有浓厚兴趣，具备较强的学习能力、理解能力、沟通能力、执行力', 1, '极度友好', '1. 负责公司基础人事工作，包括员工入转调离的协助； 2. 负责协助社招岗位的简历筛选、面试邀约、面试协助； 3. 负责协助开展培训工作； 4. 负责协助校园招聘的工资实施落地。', '招聘全流程执行, 简历筛选与面试, 员工关系支持, 校招项目运营', '本科及以上', '人力资源、工商管理、心理学、新闻学、汉语言文学等专业', '2023/2024 届在校生，每周工作日均能参加实习，无课程冲突；实习 3 个月，每周 5 天 / 周', '日常实习', '有人力资源相关实习经验者优先', '120-150元/天', '45239', '46112', 'https://www.shixiseng.com/intern/inn_pgog6esevkth?pcm=pc_SearchList&_refluxos=a10', '人力管培生类', '甲方（企业自有 HR 岗）'), ('人力资源实习生-上海（实习）', '人力资源服务 / 咨询', '上海', '民营企业', 160, 240, '1. 大学本科以上学历，能全职实习为佳； 2. 熟悉互联网行业或电商行业、人力资源、计算机或相关背景的有加分； 3. 熟练使用 Office 办公软件，尤其是 Excel、PPT； 4. 具备基础的数据分析能力与招聘流程执行能力。', '1. 具备极强的责任心和原则性，良好的人际沟通及协调能力，良好的学习能力； 2. 思维清晰，逻辑敏捷，抗压能力强，适应能力强； 3. 具备优秀的团队合作精神与服务意识。', 1, '极度友好', '1. 协助招聘工作，与招聘团队合作，参与职位发布、简历筛选和面试安排等工作，确保招聘流程高效进行； 2. 协助进行候选人的背景调查和入职资料的准备工作； 3. 员工关系管理：协助处理员工的入职、离职手续，确保系统的完整性和准确性； 4. 参与组织新员工入职培训入职引导，帮助新